elements.customCode:
(async () => {

  const params = new URLSearchParams(window.location.search);
  const nodeId = params.get('var-nodeId') ?? '';

  try {
    const resp = await fetch(
      'https://brain-v2x-madrid-cyanaccaf3fuapgp.westeurope-01.azurewebsites.net/api/toggle_simulation',
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ nodeId })
      }
    );
    if (!resp.ok) throw new Error(`HTTP ${resp.status}`);

    const isActive = params.get('var-VAR_ACTIVE') === 'true';
    const newActive = !isActive;

    context.panel.onChangeElements(
      context.panel.elements.map(el =>
        el.id === 'var_active_toggle'
          ? { ...el, buttonLabel: 'SIMULATED MODE', backgroundColor: newActive ? '#2e9e44' : '#1a5c2a', foregroundColor: '#ffffff' }
          : el
      )
    );
    context.grafana.locationService.partial({ 'var-VAR_ACTIVE': String(newActive) });
    context.grafana.notifySuccess(['MODO SIMULADO', newActive ? 'Activado' : 'Desactivado']);
  } catch (e) {
    console.error('[TOGGLE] ERROR:', e);
    context.grafana.notifyError(['Error POST', e.message]);
  }
})();

